        -ManifestPath $ManifestPath `
        -ConfigPath $ConfigPath `
        -MockLicenseFile $MockLicenseFile `
        -OutputPath $OutputPath

    if (-not $report.OverallCompliant) { exit 1 }
    if ($FailOnUnknown -and $report.Summary.unknown -gt 0) { exit 1 }
    exit 0
} catch {
    Write-Error $_
    exit 2
}

